svg.script:

launch();

function launch() {
  try {
    fetch("https://cdn.jsdelivr.net/gh/sealiee11/arctic@main/index.html?t=" + Date.now())
      .then(response => response.text())
      .then(html => {
        // Target the HTML container inside the foreignObject
        const container = document.getElementById('app-viewport');
        if (container) {
          container.innerHTML = html;

          // Extract and execute scripts within the context of the container
          container.querySelectorAll('script').forEach(oldScript => {
            const newScript = document.createElement('script');
            if (oldScript.src) {
              newScript.src = oldScript.src;
            } else {
              newScript.textContent = oldScript.textContent;
            }
            // Append directly to the document body so scripts execute properly
            document.body.appendChild(newScript);
          });
        }
      });
  } catch (error) {
    console.error('error:', error);
  }
}
